/*
 * i18n.js — shared internationalization for the login and admin pages.
 *
 * Responsibilities:
 *   - Hold the translation dictionaries for all supported languages.
 *   - Auto-detect the preferred language (localStorage > browser settings > English).
 *   - Translate static markup via `data-i18n*` attributes (applyI18n).
 *   - Translate dynamic strings via the t(key, vars) helper.
 *   - Render a language switcher (createLangSwitcher) and switch languages.
 *
 * Loaded synchronously in <head> (before common.js) so detection runs before paint.
 */

